const body = (msg.payload && typeof msg.payload === 'object') ? msg.payload : {};
const chargerId = body.chargerId != null ? String(body.chargerId) : '';
const online = Boolean(body.online);
const message = typeof body.message === 'string' ? body.message : (online ? 'Charger is online' : 'Charger is offline');
const id = 'n-' + Date.now() + '-' + Math.random().toString(36).slice(2);
const level = online ? 'success' : 'info';

let list = global.get('chargerNotificationsList') || [];
list.push({ id, chargerId, online, message, level, createdAt: new Date().toISOString() });
if (list.length > 200) list = list.slice(-200);
global.set('chargerNotificationsList', list);

msg.payload = { success: true, id };
msg.notification = { id, chargerId, online, message, level };
msg.statusCode = 200;
return msg;

const n = msg.notification;
if (!n || !n.id) return null;
// حفظ التاريخ الكامل من السيرفر: created_at = CURRENT_TIMESTAMP(3)
msg.topic = "INSERT INTO ocpp_CSGO.charger_notifications (id, charger_id, online, message, level, created_at) VALUES (?, ?, ?, ?, ?, CURRENT_TIMESTAMP(3))";
msg.payload = [n.id, n.chargerId || '', n.online ? 1 : 0, n.message || '', n.level || 'info'];
return msg;

const q = (msg.req && msg.req.query) || {};
const userId = (q.userId != null && String(q.userId).trim() !== '') ? String(q.userId).trim() : null;
const sinceRaw = (q.since != null) ? String(q.since).trim() : '';
const sinceNum = Number(sinceRaw);
const sinceIsNumber = sinceRaw !== '' && Number.isFinite(sinceNum);
const sinceStrDefault = '1970-01-01 00:00:00.000';

if (userId) {
  if (sinceIsNumber) {
    msg.topic = "SELECT n.id, n.charger_id AS chargerId, n.online, n.message, n.level, " +
      "DATE_FORMAT(n.created_at, '%Y-%m-%d %H:%i:%s.%f') AS createdAt, " +
      "(r.read_at IS NOT NULL) AS \`read\`, " +
      "DATE_FORMAT(r.read_at, '%Y-%m-%d %H:%i:%s.%f') AS readAt " +
      "FROM ocpp_CSGO.charger_notifications n " +
      "LEFT JOIN ocpp_CSGO.user_notification_read r ON r.notification_id = n.id AND r.user_id = ? " +
      "WHERE n.created_at >= FROM_UNIXTIME(?/1000) " +
      "ORDER BY n.created_at DESC LIMIT 200";
    msg.payload = [userId, sinceNum];
  } else {
    const sinceStr = sinceRaw || sinceStrDefault;
    msg.topic = "SELECT n.id, n.charger_id AS chargerId, n.online, n.message, n.level, " +
      "DATE_FORMAT(n.created_at, '%Y-%m-%d %H:%i:%s.%f') AS createdAt, " +
      "(r.read_at IS NOT NULL) AS \`read\`, " +
      "DATE_FORMAT(r.read_at, '%Y-%m-%d %H:%i:%s.%f') AS readAt " +
      "FROM ocpp_CSGO.charger_notifications n " +
      "LEFT JOIN ocpp_CSGO.user_notification_read r ON r.notification_id = n.id AND r.user_id = ? " +
      "WHERE n.created_at >= ? " +
      "ORDER BY n.created_at DESC LIMIT 200";
    msg.payload = [userId, sinceStr];
  }
} else {
  if (sinceIsNumber) {
    msg.topic = "SELECT id, charger_id AS chargerId, online, message, level, " +
      "DATE_FORMAT(created_at, '%Y-%m-%d %H:%i:%s.%f') AS createdAt " +
      "FROM ocpp_CSGO.charger_notifications " +
      "WHERE created_at >= FROM_UNIXTIME(?/1000) " +
      "ORDER BY created_at DESC LIMIT 200";
    msg.payload = [sinceNum];
  } else {
    const sinceStr = sinceRaw || sinceStrDefault;
    msg.topic = "SELECT id, charger_id AS chargerId, online, message, level, " +
      "DATE_FORMAT(created_at, '%Y-%m-%d %H:%i:%s.%f') AS createdAt " +
      "FROM ocpp_CSGO.charger_notifications " +
      "WHERE created_at >= ? " +
      "ORDER BY created_at DESC LIMIT 200";
    msg.payload = [sinceStr];
  }
}
return msg;

const rows = Array.isArray(msg.payload) ? msg.payload : [];
const data = rows.map(r => ({
  id: r.id,
  chargerId: r.chargerId,
  online: r.online === 1 || r.online === true,
  message: r.message,
  level: r.level,
  createdAt: r.createdAt,
  read: r.read === 1 || r.read === true,
  readAt: r.readAt || null
}));
msg.payload = { success: true, data };
msg.statusCode = 200;
return msg;

let raw = (msg.req && msg.req.body != null) ? msg.req.body : msg.payload;
if (typeof raw === 'string') { try { raw = JSON.parse(raw); } catch(e) { raw = {}; } }
if (typeof raw !== 'object' || raw === null) raw = {};
const body = raw;
const notificationId = (body.notificationId || body.notification_id || '').toString().trim();
const userId = body.userId != null ? Number(body.userId) : (body.user_id != null ? Number(body.user_id) : NaN);
if (!notificationId || !Number.isFinite(userId)) {
  msg.statusCode = 400;
  msg.payload = { success: false, message: 'notificationId and userId required' };
  return msg;
}
msg.topic = "INSERT INTO ocpp_CSGO.user_notification_read (user_id, notification_id, read_at) VALUES (?, ?, CURRENT_TIMESTAMP(3)) ON DUPLICATE KEY UPDATE read_at = CURRENT_TIMESTAMP(3)";
msg.payload = [userId, notificationId];
return msg;

msg.payload = { success: true, message: 'marked as read' };
msg.statusCode = 200;
return msg;

let raw = (msg.req && msg.req.body != null) ? msg.req.body : msg.payload;
if (typeof raw === 'string') { try { raw = JSON.parse(raw); } catch(e) { raw = {}; } }
if (typeof raw !== 'object' || raw === null) raw = {};
const body = raw;
const userId = body.userId != null ? Number(body.userId) : (body.user_id != null ? Number(body.user_id) : NaN);
if (!Number.isFinite(userId)) {
  msg.statusCode = 400;
  msg.payload = { success: false, message: 'userId required' };
  return msg;
}
msg.topic = "INSERT INTO ocpp_CSGO.user_notification_read (user_id, notification_id, read_at) SELECT ?, n.id, CURRENT_TIMESTAMP(3) FROM ocpp_CSGO.charger_notifications n ORDER BY n.created_at DESC LIMIT 1000 ON DUPLICATE KEY UPDATE read_at = CURRENT_TIMESTAMP(3)";
msg.payload = [userId];
return msg;

msg.payload = { success: true };
msg.statusCode = 200;
return msg;

const errMsg = msg.error && msg.error.message ? msg.error.message : (typeof msg.payload === 'string' ? msg.payload : 'Database or flow error');
const source = msg.error && msg.error.source ? msg.error.source : 'unknown';
msg.statusCode = 500;
msg.payload = { success: false, message: errMsg, _debug: { source } };
return msg;
